const inbox = $('Query — Inbox KPIs').item.json;
const audit = $('Query — Audit Events').item.json;
const dlq = $('Query — DLQ Status').item.json;

const successRate = inbox.success_rate || 0;
const costUsd = inbox.total_cost_usd || 0;
const totalMsg = inbox.total_messages || 0;
const latency = inbox.avg_latency_ms || 0;
const rejected = audit.rejected || 0;
const hitl = audit.hitl_count || 0;
const dlqPending = dlq.dlq_pending || 0;

// SLO check
const sloOk = successRate >= 95 && costUsd <= 0.50;
const statusIcon = sloOk ? '✅' : '⚠️';

const report = `📊 *COPREM Daily Report — ${new Date().toLocaleDateString('th-TH')}*

${statusIcon} *SLO Status:* ${sloOk ? 'PASS' : 'REVIEW NEEDED'}

*L8 KPIs (24h):*
• Messages: ${totalMsg}
• Success Rate: ${successRate}% ${successRate >= 95 ? '✅' : '❌ <95%'}
• API Cost: $${costUsd} ${costUsd <= 0.50 ? '✅' : '❌ >$0.50'}
• Avg Latency: ${latency}ms
• Unique Users: ${inbox.unique_users || 0}

*Security (L7):*
• Audit Events: ${audit.audit_events || 0}
• Rejected Webhooks: ${rejected}
• HITL Triggered: ${hitl}

*DLQ (L6):*
• Pending Tasks: ${dlqPending} ${dlqPending > 0 ? '⚠️' : '✅'}
• Quarantined: ${dlq.quarantined || 0}`;

return { report, slo_pass: sloOk };
